type RouteContext = { params: Promise<{ id: string }> };
type UpdatePostBody = { title?: unknown; content?: unknown };

export async function GET(_request: Request, { params }: RouteContext) {
  const { id } = await params;
  return NextResponse.json({ id: Number.parseInt(id, 10), title: `Post ${id}`, content: `This is the content for post ${id}`, createdAt: new Date().toISOString() });
}

export async function PUT(request: Request, { params }: RouteContext) {
  const { id } = await params;
  const body = (await request.json()) as UpdatePostBody;
  return NextResponse.json({ id: Number.parseInt(id, 10), title: typeof body.title === 'string' && body.title ? body.title : `Post ${id}`, content: typeof body.content === 'string' && body.content ? body.content : `Updated content for post ${id}`, updatedAt: new Date().toISOString() });
}

export async function DELETE(_request: Request, { params }: RouteContext) {
  const { id } = await params;
  return NextResponse.json({ message: `Post ${id} deleted successfully` });
}

export function OPTIONS() {
  return new NextResponse(null, { status: 204, headers: { Allow: 'GET, PUT, DELETE' } });
}

