import type { Metadata } from 'next';
import { notFound } from 'next/navigation';
import { BackButton } from '@/components/BackButton';

type Post = { id: number; title: string; body: string };
type Comment = { id: number; name: string; body: string; email: string };
type RouteParams = { id: string };

export const revalidate = 300;

async function getPost(id: string): Promise<{ post: Post; comments: Comment[] } | null> {
  const [postResponse, commentsResponse] = await Promise.all([
    fetch(`https://jsonplaceholder.typicode.com/posts/${id}`),
    fetch(`https://jsonplaceholder.typicode.com/posts/${id}/comments`),
  ]);
  if (!postResponse.ok || !commentsResponse.ok) return null;
  return {
    post: (await postResponse.json()) as Post,
    comments: (await commentsResponse.json()) as Comment[],
  };
}

export async function generateStaticParams(): Promise<RouteParams[]> {
  const response = await fetch('https://jsonplaceholder.typicode.com/posts');
  if (!response.ok) return [];
  const posts = (await response.json()) as Array<{ id: number }>;
  return posts.slice(0, 10).map(({ id }) => ({ id: String(id) }));
}

export async function generateMetadata({ params }: { params: Promise<RouteParams> }): Promise<Metadata> {
  const { id } = await params;
  const result = await getPost(id);
  if (!result) return { title: 'Post Not Found - My Blog' };
  const description = result.post.body.substring(0, 160);
  return { title: `${result.post.title} - My Blog`, description, openGraph: { title: result.post.title, description } };
}

export default async function BlogPost({ params }: { params: Promise<RouteParams> }) {
  const { id } = await params;
  const result = await getPost(id);
  if (!result) notFound();
  const { post, comments } = result;

  return (
    <article>
      <BackButton />
      <h1>{post.title}</h1>
      <p>{post.body}</p>
      <h2>Comments ({comments.length})</h2>
      <div className="comments">
        {comments.map((comment) => (
          <div key={comment.id} className="comment">
            <h3>{comment.name}</h3>
            <p>{comment.body}</p>
            <small>By: {comment.email}</small>
          </div>
        ))}
      </div>
    </article>
  );
}

